def _format_response(q: str, es_resp: Dict[str, Any], size: int, from_: int) -> Dict[str, Any]:
    hits = es_resp.get("hits", {}).get("hits", [])
    items = []
    for h in hits:
        src = h.get("_source", {}) or {}
        items.append(
            {
                "id": src.get("id"),
                "sku": src.get("sku"),
                "title": src.get("title") or src.get("name"),
                "brand": src.get("brand"),
                "price": src.get("price"),
                "currency": src.get("currency"),
                "image_url": src.get("image_url"),
                "url": src.get("url"),
                "in_stock": src.get("in_stock"),
                "rating": src.get("rating"),
                "score": h.get("_score"),
            }
        )

    took = es_resp.get("took")
    timed_out = es_resp.get("timed_out", False)

    return {
        "query": q,
        "count": len(items),
        "size": size,
        "from": from_,
        "took_ms": took,
        "timed_out": timed_out,
        "items": items,
    }


def _json_response(payload: Dict[str, Any], status: int = 200, cache_seconds: int = 0) -> Response:
    resp = Response(
        response=json.dumps(payload, separators=(",", ":"), ensure_ascii=False),
        status=status,
        mimetype="application/json",
    )
    resp.headers["X-Content-Type-Options"] = "nosniff"
    if cache_seconds > 0:
        resp.headers["Cache-Control"] = f"public, max-age={cache_seconds}"
    else:
        resp.headers["Cache-Control"] = "no-store"
    return resp


