    key = _cache_key(q, size, from_)
    cached = cache.get(key)
    if cached is not None:
        return _json_response(cached, status=200, cache_seconds=int(CACHE_TTL_SECONDS))

    t0 = time.time()
    try:
        es_resp = _es_search(q, size=size, from_=from_)
        payload = _format_response(q, es_resp, size=size, from_=from_)
        payload["latency_ms"] = int((time.time() - t0) * 1000)
        cache.set(key, payload)
        return _json_response(payload, status=200, cache_seconds=int(CACHE_TTL_SECONDS))
    except (ESConnectionError, ConnectionTimeout):
        payload = {"error": "search_unavailable", "message": "Search backend unavailable"}
        return _json_response(payload, status=503)
    except TransportError as e:
        status = 502
